snapshot.finance_core.snap_subscriptions.rawCode:
{{
    config(
        target_schema='snapshots',
        unique_key='subscription_id',
        strategy='check',
        check_cols=['plan_id', 'subscription_status', 'ended_at']
    )
}}
select * from {{ ref('stg_subscriptions') }}

model.finance_core.int_invoice_line_item.rawCode:
{{
  config(materialized='ephemeral')
}}

with invoices as (
    select * from {{ ref('stg_invoices') }}
),

plans as (
    select * from {{ ref('stg_plans') }}
),

subscriptions as (
    select * from {{ ref('stg_subscriptions') }}
)

select
    i.invoice_id,
    i.customer_id,
    i.subscription_id,
    s.plan_id,
    p.plan_name,
    p.tier,
    i.subtotal,
    i.tax,
    i.total,
    i.subtotal * 0.85 as estimated_cost,
    i.total - (i.subtotal * 0.85) as estimated_margin,
    i.issued_at,
    i.due_at,
    i.is_paid
from invoices i
left join subscriptions s on i.subscription_id = s.subscription_id
left join plans p on s.plan_id = p.plan_id

model.finance_core.int_payment_method_st.rawCode:
{{
  config(materialized='ephemeral')
}}

with payments as (
    select * from {{ ref('stg_payments') }}
    where payment_status = 'succeeded'
)

select
    customer_id,
    payment_method,
    count(*) as method_usage_count,
    sum(amount) as method_total_amount,
    min(processed_at) as first_used_at,
    max(processed_at) as last_used_at,
    row_number() over (
        partition by customer_id
        order by count(*) desc
    ) as method_rank
from payments
group by customer_id, payment_method
